\begin{aligned}
St\frac{\partial u'}{\partial t'}
+u'\frac{\partial u'}{\partial x'}
+v'\frac{\partial u'}{\partial y'}
+w'\frac{\partial u'}{\partial z'}
&=-Eu\frac{\partial p'}{\partial x'}+\frac{1}{Re}(\nabla')^2u',\\[8pt]
St\frac{\partial v'}{\partial t'}
+u'\frac{\partial v'}{\partial x'}
+v'\frac{\partial v'}{\partial y'}
+w'\frac{\partial v'}{\partial z'}
&=-Eu\frac{\partial p'}{\partial y'}+\frac{1}{Re}(\nabla')^2v',\\[8pt]
St\frac{\partial w'}{\partial t'}
+u'\frac{\partial w'}{\partial x'}
+v'\frac{\partial w'}{\partial y'}
+w'\frac{\partial w'}{\partial z'}
&=-Eu\frac{\partial p'}{\partial z'}+\frac{1}{Re}(\nabla')^2w'-\frac{1}{F},\\[8pt]
\frac{\partial u'}{\partial x'}
+\frac{\partial v'}{\partial y'}
+\frac{\partial w'}{\partial z'}&=0.
\end{aligned}

